/// Return the default database path: `$XDG_DATA_HOME/activtrak/activity.db`.
///
/// Falls back to `~/.local/share/activtrak/activity.db` on macOS/Linux when
/// `XDG_DATA_HOME` is unset.
///
/// # Errors
///
/// Returns `TrackerError::Config` if the home directory cannot be determined.
pub fn default_db_path() -> Result<PathBuf, TrackerError> {
    let base = BaseDirs::new().ok_or_else(|| {
        TrackerError::Config("cannot determine home directory for database path".to_string())
    })?;
    Ok(base.data_dir().join("activtrak").join("activity.db"))
}

/// Open (or create) a `SQLite` database at `path` and initialise the schema.

let db_path = match cli.db {
    Some(p) => p,
    None => db::default_db_path()?,
};

pub fn init_db<P: AsRef<Path>>(path: P) -> Result<Connection, TrackerError> {
    if let Some(parent) = path.as_ref().parent() {
        std::fs::create_dir_all(parent)?;
    }
    let conn = Connection::open(path)?;

