extern "C" {
    fn AXIsProcessTrusted() -> bool;
}

/// Check whether this process has macOS Accessibility (TCC) permission.
///
/// Returns `true` when the process is listed and enabled in
/// System Settings > Privacy & Security > Accessibility.
#[must_use]
pub fn has_accessibility_permission() -> bool {
    // SAFETY: `AXIsProcessTrusted` is a stable, side-effect-free C function
    // from ApplicationServices.framework, linked automatically on macOS.
    unsafe { AXIsProcessTrusted() }
}

/// Open the macOS Accessibility settings pane.
///
/// # Errors
///
/// Returns `TrackerError::Service` if the `open` command fails.
pub fn open_accessibility_settings() -> Result<(), TrackerError> {
    let status = std::process::Command::new("open")
        .arg("x-apple.systempreferences:com.apple.preference.security?Privacy_Accessibility")
        .status()
        .map_err(|e| TrackerError::Service(format!("failed to open System Settings: {e}")))?;
    if status.success() {
        Ok(())
    } else {
        Err(TrackerError::Service(format!(
            "open command exited with: {status}"
        )))
    }
}

