#[allow(clippy::unused_async)]
pub async fn poll_once(&mut self) -> Result<(), TrackerError> {
    let new_window = match self.window_detector.get_active_window() {
        Ok(w) => {
            self.consecutive_failures = 0;
            w
        }
        Err(e) => {
            self.consecutive_failures += 1;
            if self.consecutive_failures == 10 {
                tracing::warn!(
                    "Window detection failed 10 times in a row ({e}). \
                     Is Accessibility permission granted?"
                );
            } else if self.consecutive_failures % 300 == 0 {
                tracing::warn!(
                    "Window detection still failing ({} consecutive). \
                     Grant Accessibility permission and restart.",
                    self.consecutive_failures
                );
            }
            return Ok(());
        }
    };

