/// Create a minimal `.app` bundle so macOS Accessibility recognises the binary.
///
/// The bundle is placed at `~/Applications/ActivTrak.app` with a proper
/// `Info.plist` and code signature. The launchd plist should reference
/// the binary inside the bundle.
///
/// Returns the path to the executable inside the bundle.
///
/// # Errors
///
/// Returns `TrackerError::Service` if bundle creation or code-signing fails.
pub fn create_app_bundle(source_binary: &Path) -> Result<PathBuf, TrackerError> {
    let home = directories::BaseDirs::new()
        .ok_or_else(|| TrackerError::Service("cannot determine home directory".to_string()))?;
    let app_dir = home.home_dir().join("Applications/ActivTrak.app");
    let contents_dir = app_dir.join("Contents");
    let macos_dir = contents_dir.join("MacOS");
    let target_binary = macos_dir.join("activtrak");

    std::fs::create_dir_all(&macos_dir)?;
    std::fs::copy(source_binary, &target_binary)?;

    let info_plist = contents_dir.join("Info.plist");
    std::fs::write(
        &info_plist,
        r#"<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
    <key>CFBundleIdentifier</key>
    <string>com.user.activtrak</string>
    <key>CFBundleName</key>
    <string>ActivTrak</string>
    <key>CFBundleExecutable</key>
    <string>activtrak</string>
    <key>CFBundleVersion</key>
    <string>0.1.0</string>
    <key>CFBundlePackageType</key>
    <string>APPL</string>
    <key>LSUIElement</key>
    <true/>
</dict>
</plist>
"#,
    )?;

    let status = std::process::Command::new("codesign")
        .args([
            "--force",
            "--sign",
            "-",
            "--identifier",
            "com.user.activtrak",
        ])
        .arg(&app_dir)
        .status()
        .map_err(|e| TrackerError::Service(format!("failed to run codesign: {e}")))?;

    if !status.success() {
        return Err(TrackerError::Service(format!(
            "codesign exited with: {status}"
        )));
    }

    Ok(target_binary)
}

