use crate::error::TrackerError;
use crate::platform::{IdleDetector, WindowDetector, WindowInfo};
use std::ffi::{c_void, CStr};
use std::os::raw::c_char;

// ---------------------------------------------------------------------------
// Minimal Objective-C / CoreFoundation / AX FFI
// ---------------------------------------------------------------------------

#[allow(non_camel_case_types)]
type CFTypeRef = *const c_void;
#[allow(non_camel_case_types)]
type CFStringRef = *const c_void;
#[allow(non_camel_case_types)]
type AXUIElementRef = *const c_void;
#[allow(non_camel_case_types)]
type AXError = i32;
const K_AX_ERROR_SUCCESS: AXError = 0;
const K_CF_STRING_ENCODING_UTF8: u32 = 0x0800_0100;

extern "C" {
    fn AXIsProcessTrusted() -> bool;
    fn objc_getClass(name: *const c_char) -> *mut c_void;
    fn objc_msgSend(receiver: *mut c_void, sel: *const c_void, ...) -> *mut c_void;
    fn sel_registerName(name: *const c_char) -> *const c_void;
    fn CFStringGetCStringPtr(s: CFStringRef, encoding: u32) -> *const c_char;
    fn CFStringGetLength(s: CFStringRef) -> isize;
    fn CFStringGetCString(
        s: CFStringRef,
        buffer: *mut c_char,
        buffer_size: isize,
        encoding: u32,
    ) -> bool;
    fn CFRelease(cf: CFTypeRef);
    fn AXUIElementCreateApplication(pid: i32) -> AXUIElementRef;
    fn AXUIElementCopyAttributeValue(
        element: AXUIElementRef,
        attribute: CFStringRef,
        value: *mut CFTypeRef,
    ) -> AXError;
    fn CFStringCreateWithCString(
        alloc: *const c_void,
        c_str: *const c_char,
        encoding: u32,
    ) -> CFStringRef;
}

// ---------------------------------------------------------------------------
// Permission helpers
// ---------------------------------------------------------------------------

/// Check whether this process has macOS Accessibility (TCC) permission.
#[must_use]
pub fn has_accessibility_permission() -> bool {
    // SAFETY: stable, side-effect-free C function from ApplicationServices.
    unsafe { AXIsProcessTrusted() }
}

/// Open the macOS Accessibility settings pane.
///
/// # Errors
/// Returns `TrackerError::Service` if the `open` command fails.
pub fn open_accessibility_settings() -> Result<(), TrackerError> {
    let status = std::process::Command::new("open")
        .arg("x-apple.systempreferences:com.apple.preference.security?Privacy_Accessibility")
        .status()
        .map_err(|e| TrackerError::Service(format!("failed to open System Settings: {e}")))?;
    if status.success() {
        Ok(())
    } else {
        Err(TrackerError::Service(format!(
            "open command exited with: {status}"
        )))
    }
}

// ---------------------------------------------------------------------------
// CFString helpers
// ---------------------------------------------------------------------------

/// Convert a `CFStringRef` to a Rust `String` and release the ref.
///
/// # Safety
/// `s` must be a valid `CFStringRef` or null.
unsafe fn cf_string_to_owned(s: CFStringRef) -> String {
    if s.is_null() {
        return String::new();
    }
    let ptr = unsafe { CFStringGetCStringPtr(s, K_CF_STRING_ENCODING_UTF8) };
    let result = if ptr.is_null() {
        let len = unsafe { CFStringGetLength(s) };
        let buf_size = len * 4 + 1;
        let mut buf: Vec<c_char> = vec![0; buf_size.cast_unsigned()];
        if unsafe {
            CFStringGetCString(s, buf.as_mut_ptr(), buf_size, K_CF_STRING_ENCODING_UTF8)
        } {
            unsafe { CStr::from_ptr(buf.as_ptr()) }
                .to_string_lossy()
                .into_owned()
        } else {
            String::new()
        }
    } else {
        unsafe { CStr::from_ptr(ptr) }
            .to_string_lossy()
            .into_owned()
    };
    unsafe { CFRelease(s as CFTypeRef) };
    result
}

// ---------------------------------------------------------------------------
// Accessibility helpers
// ---------------------------------------------------------------------------

/// Copy a single AX attribute value. Caller must `CFRelease` the result.
///
/// # Safety
/// `element` must be a valid `AXUIElementRef` or null.
unsafe fn ax_copy_attribute(element: AXUIElementRef, attr: &str) -> Option<CFTypeRef> {
    if element.is_null() {
        return None;
    }
    // attr must be null-terminated; callers pass a `\0`-terminated literal.
    let attr_cf = unsafe {
        CFStringCreateWithCString(
            std::ptr::null(),
            attr.as_ptr().cast::<c_char>(),
            K_CF_STRING_ENCODING_UTF8,
        )
    };
    let mut value: CFTypeRef = std::ptr::null();
    let err = unsafe { AXUIElementCopyAttributeValue(element, attr_cf, &raw mut value) };
    unsafe { CFRelease(attr_cf as CFTypeRef) };
    if err == K_AX_ERROR_SUCCESS && !value.is_null() {
        Some(value)
    } else {
        None
    }
}

// ---------------------------------------------------------------------------
// Window detection (NSWorkspace + AX — no Screen Recording needed)
// ---------------------------------------------------------------------------

/// Return `(localizedName, processIdentifier)` of the frontmost app.
///
/// # Safety
/// Uses Objective-C runtime APIs.
unsafe fn frontmost_app_info() -> Result<(String, i32), TrackerError> {
    let cls = unsafe { objc_getClass(c"NSWorkspace".as_ptr()) };
    if cls.is_null() {
        return Err(TrackerError::WindowDetection(
            "NSWorkspace class not found".to_string(),
        ));
    }
    let workspace =
        unsafe { objc_msgSend(cls, sel_registerName(c"sharedWorkspace".as_ptr())) };
    if workspace.is_null() {
        return Err(TrackerError::WindowDetection(
            "NSWorkspace.sharedWorkspace returned nil".to_string(),
        ));
    }
    let app = unsafe {
        objc_msgSend(workspace, sel_registerName(c"frontmostApplication".as_ptr()))
    };
    if app.is_null() {
        return Err(TrackerError::WindowDetection(
            "frontmostApplication returned nil".to_string(),
        ));
    }

    let name_nsstr =
        unsafe { objc_msgSend(app, sel_registerName(c"localizedName".as_ptr())) };
    let app_name = if name_nsstr.is_null() {
        String::new()
    } else {
        let cstr = unsafe {
            objc_msgSend(name_nsstr, sel_registerName(c"UTF8String".as_ptr()))
        } as *const c_char;
        if cstr.is_null() {
            String::new()
        } else {
            unsafe { CStr::from_ptr(cstr) }
                .to_string_lossy()
                .into_owned()
        }
    };

    // `processIdentifier` returns i32; transmute to get the value correctly.
    let pid_fn: unsafe extern "C" fn(*mut c_void, *const c_void) -> i32 =
        unsafe { std::mem::transmute(objc_msgSend as *const ()) };
    let pid: i32 =
        unsafe { pid_fn(app, sel_registerName(c"processIdentifier".as_ptr())) };

    Ok((app_name, pid))
}

/// Return the focused window title for `pid` via the Accessibility API.
///
/// # Safety
/// Uses stable AX APIs; returns empty string on any failure.
unsafe fn ax_window_title(pid: i32) -> String {
    let ax_app = unsafe { AXUIElementCreateApplication(pid) };
    if ax_app.is_null() {
        return String::new();
    }
    let focused = unsafe { ax_copy_attribute(ax_app, "AXFocusedWindow\0") };
    unsafe { CFRelease(ax_app as CFTypeRef) };

    let focused_elem = match focused {
        Some(f) => f,
        None => return String::new(),
    };

    let title_ref = unsafe { ax_copy_attribute(focused_elem as AXUIElementRef, "AXTitle\0") };
    unsafe { CFRelease(focused_elem) };

    match title_ref {
        Some(t) => unsafe { cf_string_to_owned(t as CFStringRef) },
        None => String::new(),
    }
}

/// Detect the frontmost application and its focused window title.
///
/// Uses `NSWorkspace` for the app name and the Accessibility API for the
/// window title. Does **not** require Screen Recording permission.
fn get_active_window_native() -> Result<WindowInfo, TrackerError> {
    let (app_name, pid) = unsafe { frontmost_app_info() }?;
    if app_name.is_empty() {
        return Err(TrackerError::WindowDetection(
            "could not determine frontmost application name".to_string(),
        ));
    }
    let title = unsafe { ax_window_title(pid) };
    Ok(WindowInfo {
        app_name,
        title,
        url: None,
    })
}

// ---------------------------------------------------------------------------
// Public platform types
// ---------------------------------------------------------------------------

pub struct MacOsWindowDetector;

impl WindowDetector for MacOsWindowDetector {
    fn get_active_window(&self) -> Result<WindowInfo, TrackerError> {
        get_active_window_native()
    }
}

pub struct MacOsIdleDetector;

impl IdleDetector for MacOsIdleDetector {
    fn idle_seconds(&self) -> Result<u64, TrackerError> {
        Ok(0)
    }
}

