use crate::error::TrackerError;
use std::io::Read;
use std::path::{Path, PathBuf};

/// Return a simple FNV-1a hash of `path`'s contents, or 0 on read error.
/// Used to detect whether the source binary changed since the last install.
fn file_checksum(path: &Path) -> u64 {
    let Ok(mut f) = std::fs::File::open(path) else {
        return 0;
    };
    let mut buf = [0u8; 65536];
    let mut hash: u64 = 0xcbf2_9ce4_8422_2325;
    loop {
        match f.read(&mut buf) {
            Ok(0) | Err(_) => break,
            Ok(n) => {
                for &b in &buf[..n] {
                    hash ^= u64::from(b);
                    hash = hash.wrapping_mul(0x0000_0100_0000_01b3);
                }
            }
        }
    }
    hash
}

