const K_CF_STRING_ENCODING_UTF8: u32 = 0x0800_0100;

extern "C" {
    fn objc_getClass(name: *const c_char) -> *mut c_void;
    fn objc_msgSend(receiver: *mut c_void, sel: *const c_void, ...) -> *mut c_void;
    fn sel_registerName(name: *const c_char) -> *const c_void;
    fn CFStringGetCStringPtr(s: CFStringRef, encoding: u32) -> *const c_char;
    fn CFRelease(cf: CFTypeRef);
    fn AXUIElementCreateApplication(pid: i32) -> AXUIElementRef;
    fn AXUIElementCopyAttributeValue(element: AXUIElementRef, attribute: CFStringRef, value: *mut CFTypeRef) -> AXError;
    fn CFStringCreateWithCString(alloc: *const c_void, c_str: *const c_char, encoding: u32) -> CFStringRef;
}

fn main() {
    unsafe {
        let cls = objc_getClass(c"NSWorkspace".as_ptr());
        let ws = objc_msgSend(cls, sel_registerName(c"sharedWorkspace".as_ptr()));
        let app = objc_msgSend(ws, sel_registerName(c"frontmostApplication".as_ptr()));

        let name = objc_msgSend(app, sel_registerName(c"localizedName".as_ptr()));
        let cstr = objc_msgSend(name, sel_registerName(c"UTF8String".as_ptr())) as *const c_char;
        let app_name = CStr::from_ptr(cstr).to_string_lossy();

        let pid_fn: unsafe extern "C" fn(*mut c_void, *const c_void) -> i32 = std::mem::transmute(objc_msgSend as *const ());
        let pid = pid_fn(app, sel_registerName(c"processIdentifier".as_ptr()));

