        let ax = AXUIElementCreateApplication(pid);
        let attr = CFStringCreateWithCString(std::ptr::null(), "AXFocusedWindow\0".as_ptr() as *const c_char, K_CF_STRING_ENCODING_UTF8);
        let mut win: CFTypeRef = std::ptr::null();
        let err = AXUIElementCopyAttributeValue(ax, attr, &raw mut win);
