// ---------------------------------------------------------------------------
// NSApplication / run-loop bootstrap
// ---------------------------------------------------------------------------

/// Initialise `NSApplication` as an accessory agent (no Dock icon, no menu
/// bar) and call it at most once per process via `std::sync::Once`.
///
/// Without this, `NSWorkspace.frontmostApplication` never receives workspace
/// change notifications from the OS event dispatcher, so it always returns a
/// stale value in background daemons.
pub fn ensure_nsapp_initialized() {
    use std::sync::Once;
    static INIT: Once = Once::new();
    INIT.call_once(|| {
        // SAFETY: NSApplication Objective-C runtime calls; safe to call once
        // per process on the main thread.
        unsafe {
            let cls = objc_getClass(c"NSApplication".as_ptr());
            if cls.is_null() {
                return;
            }
            let app = objc_msgSend(cls, sel_registerName(c"sharedApplication".as_ptr()));
            if app.is_null() {
                return;
            }
            // NSApplicationActivationPolicyAccessory = 1 (no Dock icon)
            let policy_fn: unsafe extern "C" fn(*mut c_void, *const c_void, isize) -> bool =
                std::mem::transmute(objc_msgSend as *const ());
            policy_fn(
                app,
                sel_registerName(c"setActivationPolicy:".as_ptr()),
                1, // NSApplicationActivationPolicyAccessory
            );
        }
    });
}

/// Pump the CoreFoundation run loop for 50 ms so that pending workspace
/// notifications are dispatched before we query `frontmostApplication`.
fn pump_run_loop() {
    // SAFETY: CFRunLoopRunInMode is a stable CF function; 50 ms is short
    // enough not to block the poll loop meaningfully.
    unsafe {
        CFRunLoopRunInMode(kCFRunLoopDefaultMode, 0.05, false);
    }
}

